dn(ContainerNodeFooter, "ContainerNode.Footer");
dn(ContainerNodeResourceGroup, "ContainerNode.ResourceGroup");
dn(ContainerNodeReplicas, "ContainerNode.Replicas");

export type {
  ContainerNodeDeleteDialogPanelProps,
  ContainerNodeDeleteDialogProps,
} from "./container-node.delete-dialog";
export type {
  ContainerNodeScaleDialogPanelProps,
  ContainerNodeScaleDialogProps,
} from "./container-node.scale-dialog";

"use client";

import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@workspace/ui/components/alert-dialog";
import { Button } from "@workspace/ui/components/button";
import { cn } from "@workspace/ui/lib/utils";

const DELETE_TITLE = "Delete container?";

function deleteDescriptionText(name: string) {
  return `This will permanently delete "${name}". This action cannot be undone.`;
}

export interface ContainerNodeDeleteDialogPanelProps {
  className?: string;
  name: string;
  onCancel: () => void;
  onConfirmDelete?: () => void;
}

/** In-flow panel (no portal). Use in previews or custom layouts. */
export function ContainerNodeDeleteDialogPanel({
  className,
  name,
  onCancel,
  onConfirmDelete,
}: ContainerNodeDeleteDialogPanelProps) {
  return (
    <div
      className={cn(
        "grid w-full max-w-xs gap-6 rounded-xl bg-background p-6 ring-1 ring-foreground/10",
        className
      )}
    >
      <div className="grid grid-rows-[auto_1fr] place-items-center gap-1.5 text-center">
        <h3 className="font-medium text-lg">{DELETE_TITLE}</h3>
        <p className="text-balance text-muted-foreground text-sm md:text-pretty">
          {deleteDescriptionText(name)}
        </p>
      </div>
      <div className="grid grid-cols-2 gap-2 sm:flex sm:flex-row sm:justify-end">
        <Button className="text-xs" onClick={onCancel} variant="outline">
          Cancel
        </Button>
        <Button
          className="text-xs"
          onClick={() => {
            onConfirmDelete?.();
          }}
          variant="destructive"
        >
          Delete
        </Button>
      </div>
    </div>
  );
}

ContainerNodeDeleteDialogPanel.displayName = "ContainerNodeDeleteDialogPanel";

export interface ContainerNodeDeleteDialogProps {
  /** Workload display name shown in the copy. */
  name: string;
  onConfirmDelete?: () => void;
  onOpenChange: (open: boolean) => void;
  open: boolean;
}

export function ContainerNodeDeleteDialog({
  open,
  onOpenChange,
  name,
  onConfirmDelete,
}: ContainerNodeDeleteDialogProps) {
  return (
    <AlertDialog onOpenChange={onOpenChange} open={open}>
      <AlertDialogContent size="sm">
        <AlertDialogHeader>
          <AlertDialogTitle>{DELETE_TITLE}</AlertDialogTitle>
          <AlertDialogDescription>
            This will permanently delete &quot;{name}&quot;. This action cannot
            be undone.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel className="text-xs">Cancel</AlertDialogCancel>
          <AlertDialogAction
            className="text-xs"
            onClick={() => {
              onConfirmDelete?.();
              onOpenChange(false);
            }}
            variant="destructive"
          >
            Delete
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

ContainerNodeDeleteDialog.displayName = "ContainerNodeDeleteDialog";

"use client";

import { Dialog, DialogContent } from "@workspace/ui/components/dialog";
import { ScaleSlider } from "@workspace/ui/components/scale-slider/scale-slider";
import { cn } from "@workspace/ui/lib/utils";
import { useEffect, useMemo, useState } from "react";

export interface ContainerNodeScaleDialogPanelProps {
  className?: string;
  draft: number;
  max: number;
  onDraftChange: (next: number) => void;
  onScale?: (nextReplicas: number) => void;
}

/** In-flow scale controls (no portal). Use in previews or custom layouts. */
export function ContainerNodeScaleDialogPanel({
  className,
  draft,
  max,
  onDraftChange,
  onScale,
}: ContainerNodeScaleDialogPanelProps) {
  return (
    <div
      className={cn("flex flex-col items-center justify-center p-6", className)}
    >
      <ScaleSlider.Root
        max={max}
        maxDecimals={0}
        min={0}
        onValueChange={onDraftChange}
        step={1}
        value={draft}
        valueDisplay="number"
      >
        <ScaleSlider.Stack className="w-full max-w-xs">
          <ScaleSlider.Header>
            <ScaleSlider.Label>Replicas</ScaleSlider.Label>
            <ScaleSlider.Value />
          </ScaleSlider.Header>
          <ScaleSlider.Control
            onValueCommit={(vals) => {
              const n = vals[0];
              if (n !== undefined) {
                onScale?.(n);
              }
            }}
          >
            <ScaleSlider.Track>
              <ScaleSlider.Range />
            </ScaleSlider.Track>
            <ScaleSlider.Thumb />
          </ScaleSlider.Control>
        </ScaleSlider.Stack>
      </ScaleSlider.Root>
    </div>
  );
}

ContainerNodeScaleDialogPanel.displayName = "ContainerNodeScaleDialogPanel";

export interface ContainerNodeScaleDialogProps {
  /** Upper bound for the slider (defaults to at least 20 and the current draft). */
  maxReplicas?: number;
  onOpenChange: (open: boolean) => void;
  /** Called when the user releases the thumb with a new replica count. */
  onScale?: (nextReplicas: number) => void;
  open: boolean;
  /** Current replica count when the dialog opens or `replicas` updates while open. */
  replicas: number;
}

export function ContainerNodeScaleDialog({
  open,
  onOpenChange,
  replicas,
  onScale,
  maxReplicas: maxReplicasProp,
}: ContainerNodeScaleDialogProps) {
  const [draft, setDraft] = useState(replicas);

  useEffect(() => {
    if (open) {
      setDraft(replicas);
    }
  }, [open, replicas]);

  const scaleMax = useMemo(
    () => maxReplicasProp ?? Math.max(20, replicas, draft, 1),
    [draft, maxReplicasProp, replicas]
  );

  return (
    <Dialog onOpenChange={onOpenChange} open={open}>
      <DialogContent
        className="gap-0 p-0 sm:max-w-sm"
        closeButtonClassName="top-2 right-2 size-5"
      >
        <ContainerNodeScaleDialogPanel
          draft={draft}
          max={scaleMax}
          onDraftChange={setDraft}
          onScale={onScale}
        />
      </DialogContent>
    </Dialog>
  );
}

ContainerNodeScaleDialog.displayName = "ContainerNodeScaleDialog";

import {
  type CrossplaneServiceStatusPhase,
  STATUS_PHASE_INDICATORS,
  STATUS_PHASES,
} from "../schemas/crossplane-status-schema";

export type { CrossplaneServiceStatusPhase } from "../schemas/crossplane-status-schema";

/**
 * Maps a raw status string (e.g. from a CRD `status.phase`) to a known phase key.
 * Matching is case-insensitive; leading/trailing whitespace is trimmed.
 */
export function getToneForStatus(
  status: string | null | undefined
): CrossplaneServiceStatusPhase | undefined {
  if (status == null || status === "") {
    return undefined;
  }
  const normalized = status.trim().toLowerCase();
  if (normalized in STATUS_PHASES) {
    return normalized as CrossplaneServiceStatusPhase;
  }
  return undefined;
}

export function getStatusTextClass(tone: CrossplaneServiceStatusPhase): string {
  return STATUS_PHASES[tone];
}

export function getStatusIndicatorClass(
  tone: CrossplaneServiceStatusPhase
): string {
  return STATUS_PHASE_INDICATORS[tone];
}
